async function resolveNodeModulesBase(cwd: string): Promise<string> {
  if (await exists(path.resolve(process.cwd(), 'prisma/schema.prisma'))) {
    return process.cwd()
  }
  if (path.relative(process.cwd(), cwd) === 'prisma' && (await exists(path.resolve(process.cwd(), 'package.json')))) {
    return process.cwd()
  }
  if (await exists(path.resolve(cwd, 'node_modules'))) {
    return cwd
  }
  if (await exists(path.resolve(cwd, '../node_modules'))) {
    return path.join(cwd, '../')
  }
  if (await exists(path.resolve(cwd, 'package.json'))) {
    return cwd
  }
  if (await exists(path.resolve(cwd, '../package.json'))) {
    return path.join(cwd, '../')
  }
  return cwd
}

export class FormattedString implements ErrorBasicBuilder {
  private isUnderlined = false
  private color: ColorFn = (str) => str
  constructor(public contents: string) {}

  underline(): this {
    this.isUnderlined = true
    return this
  }

  setColor(color: ColorFn): this {
    this.color = color
    return this
  }

  write(writer: ErrorWriter): void {
    const paddingSize = writer.getCurrentLineLength()
    writer.write(this.color(this.contents))
    if (this.isUnderlined) {
      writer.afterNextNewline(() => {
        writer.write(' '.repeat(paddingSize)).writeLine(this.color('~'.repeat(this.contents.length)))
      })
    }
  }
}

export async function execCommandCountLines(
  command: string,
  args: string[],
  options?: Parameters<typeof execa>[1]
) {
  const process = execa(command, args, { buffer: false, ...options });
  if (!process.stdout) {
    // eslint-disable-next-line local-rules/no-uncategorized-errors
    throw new Error('Unexpected missing stdout');
  }

  let lineCount = 0;
  const rl = createInterface(process.stdout);
  rl.on('line', () => {
    lineCount += 1;
  });

  // If the process errors, this will throw
  await process;

  rl.close();

  return lineCount;
}

export const getActualPackageJson = async (
