private async _race(promises: Promise<any>[], safe: boolean, defaultValue?: any): Promise<any> {
  const terminatePromise = new ManualPromise<Error>();
  const frames = captureRawStack();
  if (this._terminateError)
    terminatePromise.resolve(this._terminateError);
  if (this._closeError)
    terminatePromise.resolve(cloneError(this._closeError, frames));
  this._terminatePromises.set(terminatePromise, frames);
  try {
    return await Promise.race([
      terminatePromise.then(e => safe ? defaultValue : Promise.reject(e)),
      ...promises
    ]);
  } finally {
    this._terminatePromises.delete(terminatePromise);
  }
}

export function createOutputMiddleware<TOutput>(parse: ParseFn<TOutput>) {
  const outputMiddleware: AnyMiddlewareFunction =
    async function outputValidatorMiddleware({ next }) {
      const result = await next();
      if (!result.ok) {
        // pass through failures without validating
        return result;
      }
      try {
        const data = await parse(result.data);
        return {
          ...result,
          data,
        };
      } catch (cause) {
        throw new TRPCError({
          message: 'Output validation failed',
          code: 'INTERNAL_SERVER_ERROR',
          cause,
        });
      }
    };
  outputMiddleware._type = 'output';
  return outputMiddleware;
}

